<?php $adminTitle='LMS Modules'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ $pdo->prepare('INSERT INTO lms_modules (course_id,title,description,sort_order,status) VALUES (?,?,?,?,?)')->execute([(int)$_POST['course_id'],trim($_POST['title']),trim($_POST['description']),(int)$_POST['sort_order'],$_POST['status']]); header('Location: lms-modules.php'); exit; } $courses=get_courses($pdo,false); $rows=$pdo->query('SELECT m.*,c.title course_title FROM lms_modules m JOIN lms_courses c ON c.id=m.course_id ORDER BY c.title,m.sort_order')->fetchAll(); ?><h1>Modules</h1><form class="glass-card mb-4" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><div class="row g-3"><div class="col-md-4"><select class="form-select" name="course_id"><?php foreach($courses as $c): ?><option value="<?= (int)$c['id']; ?>"><?= e($c['title']); ?></option><?php endforeach; ?></select></div><div class="col-md-4"><input class="form-control" name="title" placeholder="Module title" required></div><div class="col-md-2"><input class="form-control" name="sort_order" value="1"></div><div class="col-md-2"><select class="form-select" name="status"><option>Published</option><option>Draft</option></select></div><div class="col-12"><textarea class="form-control" name="description" placeholder="Module description"></textarea></div><div class="col-12"><button class="btn btn-premium">Add Module</button></div></div></form><div class="glass-card"><table class="table table-dark"><tr><th>Course</th><th>Module</th><th>Status</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['course_title']); ?></td><td><?= e($r['title']); ?></td><td><?= e($r['status']); ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>